class RandomizedSet:
    def __init__(self):
        self.nums = []; self.pos = {}
    def insert(self, val):
        if val in self.pos: return False
        self.pos[val] = len(self.nums); self.nums.append(val); return True
    def remove(self, val):
        if val not in self.pos: return False
        idx, last = self.pos[val], self.nums[-1]
        self.nums[idx], self.pos[last] = last, idx
        self.nums.pop(); del self.pos[val]; return True
    def getRandom(self):
        return random.choice(self.nums)

